import { Component, h, State } from '@stencil/core';

const LS_CROQUETTE_PRICE = 'dofunity-croquette-price-kamas';
const LS_FAMILIER_BUDGET = 'dofunity-familier100-budget-kamas';

export type CroquetteReference = {
  croquetteItemId: number | null;
  croquetteName: string;
  croquetteFileXpPerUnit: number;
  croquetteUnitPriceHdv: number | null;
  croquetteUnitPriceUsed: number | null;
  croquettePriceSource: 'manuel' | 'hdv' | null;
  croquetteUnitsForFamilier100: number;
  familier100TotalPetXp: number;
  /** Budget total kamas que tu acceptes pour le parcours 1 → 100 (sert au plafond / u). */
  familier100BudgetKamas: number | null;
  costFullCroquettePathKamas: number | null;
};

export type ResourceProfitRow = {
  id: number;
  name: string;
  lvl: number | null;
  categoryId: number | null;
  category: { id: number; name: string; rootCategory?: { id: number; name: string } } | null;
  xpPerUnit: number;
  unitPrice: number;
  xpPerPrice: number;
  unitsForSameFamilierProgress: number | null;
  costSameFamilierProgressKamas: number | null;
  benefitVsCroquettesKamas: number | null;
  maxProfitableUnitPriceKamas: number | null;
  maxUnitPriceForBudgetKamas: number | null;
};

@Component({
  tag: 'app-resources-profit',
  styleUrl: 'app-resources-profit.css',
  shadow: false,
})
export class AppResourcesProfit {
  API_URL = '/api';
  readonly fetchLimit = 800;

  @State() reference: CroquetteReference | null = null;
  @State() rows: ResourceProfitRow[] = [];
  @State() isLoading = true;
  @State() errorMessage = '';
  @State() croquettePriceInput = '';
  @State() familierBudgetInput = '';

  async componentWillLoad() {
    try {
      const savedC = localStorage.getItem(LS_CROQUETTE_PRICE);
      if (savedC != null && savedC !== '') {
        this.croquettePriceInput = savedC;
      }
      const savedB = localStorage.getItem(LS_FAMILIER_BUDGET);
      if (savedB != null && savedB !== '') {
        this.familierBudgetInput = savedB;
      }
    } catch {
      /**/
    }
    await this.loadData();
  }

  parsePriceInput(raw: string): number | null {
    const n = parseFloat(raw.replace(/\s/g, '').replace(',', '.'));
    if (!Number.isFinite(n) || n <= 0) return null;
    return n;
  }

  async loadData() {
    this.isLoading = true;
    this.errorMessage = '';
    try {
      const params = new URLSearchParams();
      params.set('limit', String(this.fetchLimit));

      const manualC = this.parsePriceInput(this.croquettePriceInput.trim());
      if (manualC != null) {
        params.set('croquettePriceKamas', String(manualC));
      }

      const budget = this.parsePriceInput(this.familierBudgetInput.trim());
      if (budget != null) {
        params.set('familier100BudgetKamas', String(budget));
      }

      const res = await fetch(
        `${this.API_URL}/items/resources/profitability?${params.toString()}`
      );
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const body = await res.json();
      if (Array.isArray(body)) {
        this.rows = body;
        this.reference = null;
      } else {
        this.reference = body.reference ?? null;
        this.rows = body.rows ?? [];
      }
    } catch (e) {
      console.error(e);
      this.errorMessage =
        'Impossible de charger la rentabilité. Vérifie que la migration XP est appliquée et que npm run db:import-xp a été exécuté.';
    } finally {
      this.isLoading = false;
    }
  }

  applyParams = () => {
    const cTrim = this.croquettePriceInput.trim();
    const bTrim = this.familierBudgetInput.trim();
    try {
      if (cTrim === '') localStorage.removeItem(LS_CROQUETTE_PRICE);
      else localStorage.setItem(LS_CROQUETTE_PRICE, cTrim);
      if (bTrim === '') localStorage.removeItem(LS_FAMILIER_BUDGET);
      else localStorage.setItem(LS_FAMILIER_BUDGET, bTrim);
    } catch {
      /**/
    }
    this.loadData();
  };

  clearCroquetteOverride = () => {
    this.croquettePriceInput = '';
    try {
      localStorage.removeItem(LS_CROQUETTE_PRICE);
    } catch {
      /**/
    }
    this.loadData();
  };

  clearBudget = () => {
    this.familierBudgetInput = '';
    try {
      localStorage.removeItem(LS_FAMILIER_BUDGET);
    } catch {
      /**/
    }
    this.loadData();
  };

  formatFr(n: number, maximumFractionDigits: number): string {
    if (!Number.isFinite(n)) return '—';
    return n.toLocaleString('fr-FR', {
      maximumFractionDigits,
      minimumFractionDigits: 0,
    });
  }

  formatRatio(n: number): string {
    if (!Number.isFinite(n)) return '—';
    if (n < 0.0001) return n.toExponential(2);
    return n.toFixed(8).replace(/\.?0+$/, '');
  }

  formatKamas(n: number | null | undefined): string {
    if (n == null || !Number.isFinite(n)) return '—';
    return `${this.formatFr(Math.round(n), 0)} k`;
  }

  formatQty(n: number | null | undefined): string {
    if (n == null || !Number.isFinite(n)) return '—';
    const rounded = Math.round(n);
    if (Math.abs(n - rounded) < 1e-6) return this.formatFr(rounded, 0);
    return this.formatFr(n, 4);
  }

  formatMaxPrice(n: number | null | undefined): string {
    if (n == null || !Number.isFinite(n)) return '—';
    if (n >= 1000) return this.formatFr(Math.floor(n), 0);
    return this.formatFr(n, 2);
  }

  render() {
    const ref = this.reference;
    const hasCroquetteRefPrice =
      ref?.croquetteUnitPriceUsed != null &&
      Number.isFinite(ref.croquetteUnitPriceUsed) &&
      ref.croquetteUnitPriceUsed > 0;
    const hasBudget =
      ref?.familier100BudgetKamas != null &&
      Number.isFinite(ref.familier100BudgetKamas) &&
      ref.familier100BudgetKamas > 0;

    return (
      <div class="resources-profit">
        <h1>Rentabilité des ressources (XP par kamas)</h1>

        <div class="params-form">
          <label>
            <span class="label-text">Budget total (kamas) pour familier 1 → 100</span>
            <input
              type="text"
              inputMode="numeric"
              placeholder="ex. 45 000 000 — sert au plafond d’achat / u"
              value={this.familierBudgetInput}
              onInput={(e) => {
                this.familierBudgetInput = (e.target as HTMLInputElement).value;
              }}
              onKeyDown={(e) => {
                if (e.key === 'Enter') this.applyParams();
              }}
            />
          </label>
          <label>
            <span class="label-text">Prix d’une croquette enrichie (kamas / u)</span>
            <input
              type="text"
              inputMode="decimal"
              placeholder="ex. 125000 ou vide = HDV"
              value={this.croquettePriceInput}
              onInput={(e) => {
                this.croquettePriceInput = (e.target as HTMLInputElement).value;
              }}
              onKeyDown={(e) => {
                if (e.key === 'Enter') this.applyParams();
              }}
            />
          </label>
          <div class="params-actions">
            <button type="button" class="btn-apply" onClick={() => this.applyParams()}>
              Appliquer
            </button>
            <button type="button" class="btn-clear" onClick={() => this.clearBudget()}>
              Effacer budget
            </button>
            <button type="button" class="btn-clear" onClick={() => this.clearCroquetteOverride()}>
              HDV croquettes
            </button>
          </div>
          <p class="form-hint">
            API : <code>?familier100BudgetKamas=</code> (budget total),{' '}
            <code>?croquettePriceKamas=</code> (prix / croquette). Le plafond d’achat suit ton budget quand il est
            renseigné : <code>prix max / u = budget × (XP / u) ÷ 179 592</code>.
          </p>
        </div>

        {ref ? (
          <section class="ref-block">
            <h2>Comparaison familier niveau 100</h2>
            <p>
              Pour monter un familier du niveau 1 au 100 avec uniquement des <strong>{ref.croquetteName}</strong>, il
              faut <strong>{this.formatFr(ref.croquetteUnitsForFamilier100, 3)}</strong> croquettes (nombre décimal :
              359&nbsp;virgule&nbsp;184), soit <strong>{this.formatFr(ref.familier100TotalPetXp, 0)}</strong> XP familier
              au total.
            </p>
            <p>
              Les valeurs <strong>XP</strong> du fichier correspondent à l’XP familier par unité (ex. croquette :{' '}
              {this.formatFr(ref.croquetteFileXpPerUnit, 0)}). Unités pour le même parcours :{' '}
              <code>{this.formatFr(ref.familier100TotalPetXp, 0)} ÷ (XP / u)</code>.
            </p>
            {hasBudget ? (
              <p class="ref-formula">
                <strong>Budget utilisé</strong> : {this.formatKamas(ref.familier100BudgetKamas)} au total pour le 1 →
                100. <strong>Prix max / u</strong> par ressource :{' '}
                <code>
                  {this.formatFr(ref.familier100BudgetKamas, 0)} × (XP / u) ÷{' '}
                  {this.formatFr(ref.familier100TotalPetXp, 0)}
                </code>
                . Le prix HDV est coloré s’il dépasse ce plafond.
              </p>
            ) : null}
            <p class="ref-costs">
              <span>
                Prix croquette utilisé :{' '}
                <strong>
                  {hasCroquetteRefPrice
                    ? `${this.formatFr(ref.croquetteUnitPriceUsed, 0)} k / u`
                    : '—'}
                </strong>
                {ref.croquettePriceSource === 'manuel' ? (
                  <span class="muted"> (saisie)</span>
                ) : ref.croquettePriceSource === 'hdv' ? (
                  <span class="muted"> (HDV)</span>
                ) : null}
                {ref.croquetteUnitPriceHdv != null && ref.croquettePriceSource === 'manuel' ? (
                  <span class="muted"> — HDV : {this.formatFr(ref.croquetteUnitPriceHdv, 0)} k / u</span>
                ) : null}
              </span>
            </p>
            <p class="ref-costs">
              <span>
                Coût tout en croquettes (référence) :{' '}
                <strong>{this.formatKamas(ref.costFullCroquettePathKamas)}</strong>
              </span>
              {!hasCroquetteRefPrice ? (
                <span class="alert inline">
                  {' '}
                  Indique un prix de croquette ou un prix HDV en base pour comparer aux croquettes.
                </span>
              ) : null}
            </p>
            <p class="ref-formula">
              <strong>Prix max / u vs croquettes</strong> :{' '}
              <code>
                (359,184 × prix croquette × XP / u) ÷ {this.formatFr(ref.familier100TotalPetXp, 0)}
              </code>
              {hasBudget ? <span class="muted"> (colonne séparée si budget renseigné)</span> : null}.
            </p>
          </section>
        ) : null}

        <p class="lead">
          Classement par <strong>gain vs croquettes</strong> quand le prix croquette est connu, puis par ratio XP /
          prix.
        </p>

        {this.errorMessage ? (
          <p class="alert">{this.errorMessage}</p>
        ) : this.isLoading ? (
          <p>Chargement…</p>
        ) : this.rows.length === 0 ? (
          <p>
            Aucune ressource avec XP et prix. Lance la migration, puis{' '}
            <code>npm run db:import-xp</code>, et assure-toi que les prix moyens sont peuplés.
          </p>
        ) : (
          <table class="table">
            <thead>
              <tr>
                <th>#</th>
                <th>Ressource</th>
                <th>Catégorie</th>
                <th>Niv.</th>
                <th>XP / unité</th>
                <th>Prix HDV / u</th>
                {hasBudget ? <th>Prix max / u (budget)</th> : null}
                <th>Prix max / u {hasBudget ? '(croquettes)' : ''}</th>
                <th>XP / prix</th>
                <th>Unités (équiv. familier 100)</th>
                <th>Coût équiv. familier 100</th>
                <th>Gain vs croquettes</th>
              </tr>
            </thead>
            <tbody>
              {this.rows.map((row, i) => {
                const gain = row.benefitVsCroquettesKamas;
                const gainClass =
                  gain != null && Number.isFinite(gain)
                    ? gain > 0
                      ? 'gain-pos'
                      : gain < 0
                        ? 'gain-neg'
                        : ''
                    : '';
                const limitBudget = row.maxUnitPriceForBudgetKamas;
                const limitCroq = row.maxProfitableUnitPriceKamas;
                const primaryLimit = hasBudget ? (limitBudget ?? limitCroq) : limitCroq;
                const overMax =
                  primaryLimit != null &&
                  Number.isFinite(primaryLimit) &&
                  Number.isFinite(row.unitPrice) &&
                  row.unitPrice > primaryLimit;
                return (
                  <tr key={row.id}>
                    <td>{i + 1}</td>
                    <td>{row.name}</td>
                    <td>{row.category?.name ?? '—'}</td>
                    <td>{row.lvl ?? '—'}</td>
                    <td>{row.xpPerUnit}</td>
                    <td class={`num ${overMax ? 'price-over-max' : ''}`}>
                      {this.formatFr(row.unitPrice, 0)}
                    </td>
                    {hasBudget ? (
                      <td class="num max-price">{this.formatMaxPrice(limitBudget)}</td>
                    ) : null}
                    <td class="num max-price">{this.formatMaxPrice(limitCroq)}</td>
                    <td class="ratio">{this.formatRatio(row.xpPerPrice)}</td>
                    <td class="num">{this.formatQty(row.unitsForSameFamilierProgress)}</td>
                    <td class="num">{this.formatKamas(row.costSameFamilierProgressKamas)}</td>
                    <td class={`num ${gainClass}`}>
                      {gain != null && Number.isFinite(gain) ? this.formatKamas(gain) : '—'}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>
    );
  }
}
